import graphene
from flask import Flask, jsonify
from graphene_sqlalchemy import SQLAlchemyObjectType, SQLAlchemyQueryMixin
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

app = Flask(__name__)
engine = create_engine('sqlite:///products.db')
Session = sessionmaker(bind=engine)
session = Session()

class Product(SQLAlchemyObjectType):
    class Meta:
        model = ProductModel
        interfaces = (graphene.relay.Node,)

class Category(SQLAlchemyObjectType):
    class Meta:
        model = CategoryModel
        interfaces = (graphene.relay.Node,)

class Review(SQLAlchemyObjectType):
    class Meta:
        model = ReviewModel
        interfaces = (graphene.relay.Node,)

class Query(graphene.ObjectType):
    product = graphene.Field(Product)
    products = graphene.List(Product)
    category = graphene.Field(Category)
    categories = graphene.List(Category)
    reviews = graphene.List(Review)

    def resolve_product(self, info, id):
        return Product.get(id=id)

    def resolve_products(self, info):
        return session.query(ProductModel).all()

    def resolve_category(self, info, id):
        return Category.get(id=id)

    def resolve_categories(self, info):
        return session.query(CategoryModel).all()

    def resolve_reviews(self, info, product_id=None):
        if product_id:
            return session.query(ReviewModel).filter_by(product_id=product_id).all()
        else:
            return []

class CreateProduct(graphene.Mutation):
    class Arguments:
        name = graphene.String(required=True)
        description = graphene.String()

    product = graphene.Field(Product)

    def mutate(self, info, name, description):
        product = ProductModel(name=name, description=description)
        session.add(product)
        session.commit()
        return CreateProduct(product=product)

class Mutation(graphene.ObjectType):
    create_product = CreateProduct.Field()

schema = graphene.Schema(query=Query, mutation=Mutation, types=[Product, Category, Review])

@app.route('/graphql', methods=['GET'])
def graphql_server():
    data = {'query': 'query { products { name description } }'}
    result = schema.execute(data['query'])
    return jsonify(graphene.json.dumps(result.data))

if __name__ == '__main__':
    app.run(debug=True)